import { useState, useEffect } from 'react';

interface Product {
  id: string;
  name: string;
  price: number;
  rating: number;
  brand: string;
  image: string;
}

const useFetchProducts = (category: string, filters: { price?: number; rating?: number; brand?: string }, sort: string) => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchProducts = async () => {
      setLoading(true);
      try {
        const response = await fetch(`/api/products?category=${category}&sort=${sort}`);
        if (!response.ok) {
          throw new Error('Failed to fetch products');
        }
        const data = await response.json();
        const filteredProducts = data.filter((product: Product) => {
          return (
            (!filters.price || product.price <= filters.price) &&
            (!filters.rating || product.rating >= filters.rating) &&
            (!filters.brand || product.brand === filters.brand)
          );
        });
        setProducts(filteredProducts);
      } catch (error) {
        setError(error.message);
      } finally {
        setLoading(false);
      }
    };

    fetchProducts();
  }, [category, filters, sort]);

  return { products, loading, error };
};

export default useFetchProducts;

